extension EngineError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeEngineError: FfiConverterRustBuffer {
    typealias SwiftType = EngineError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> EngineError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .TokioError(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Device(
            try FfiConverterTypeDeviceError.read(from: &buf)
            )
        case 3: return .Keyring(
            try FfiConverterTypeKeyringError.read(from: &buf)
            )
        case 4: return .Storage(
            try FfiConverterTypeStorageError.read(from: &buf)
            )
        case 5: return .Registry(
            try FfiConverterTypeRegistryError.read(from: &buf)
            )
        case 6: return .UnableToCreateBackend
        case 7: return .BackendNotFound
        case 8: return .UnableToGetDownloaderProgressStream
        case 9: return .ChatSession(
            try FfiConverterTypeChatSessionError.read(from: &buf)
            )
        case 10: return .ClassificationSession(
            try FfiConverterTypeClassificationSessionError.read(from: &buf)
            )
        case 11: return .TextToSpeechSession(
            try FfiConverterTypeTextToSpeechSessionError.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: EngineError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .TokioError(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Device(v1):
            writeInt(&buf, Int32(2))
            FfiConverterTypeDeviceError.write(v1, into: &buf)
            
        
        case let .Keyring(v1):
            writeInt(&buf, Int32(3))
            FfiConverterTypeKeyringError.write(v1, into: &buf)
            
        
        case let .Storage(v1):
            writeInt(&buf, Int32(4))
            FfiConverterTypeStorageError.write(v1, into: &buf)
            
        
        case let .Registry(v1):
            writeInt(&buf, Int32(5))
            FfiConverterTypeRegistryError.write(v1, into: &buf)
            
        
        case .UnableToCreateBackend:
            writeInt(&buf, Int32(6))
        
        
